542→      setSettings(newSettings);
543→      if (
544→        newSettings.appearance === 'dark' ||
545→        newSettings.appearance === 'light' ||
546→        newSettings.appearance === 'system'
547→      ) {
548→        setTheme(newSettings.appearance);
549→      }
