557→
558→  const handleTabChange = useCallback((value: string) => {
559→    if (isSettingsTab(value)) {
560→      setActiveTab(value);
561→      setQuery('');
562→    }
563→  }, []);
564→
565→  const handleToggleExtension = useCallback((id: string) => {
566→    setExtensions(prev =>
567→      prev.map(ext =>
568→        ext.id === id
