606→          <path
607→            d="M12 13V22M16 13V22M20 13V22M10 10H22M13 10V9C13 8.45 13.45 8 14 8H18C18.55 8 19 8.45 19 9V10"
608→            stroke="currentColor"
609→            strokeWidth="1.5"
610→            strokeLinecap="round"
611→            strokeLinejoin="round"
612→          />
613→        </svg>
614→      ),
615→      primaryAction: {
616→        label: 'Reset',
617→        style: 'destructive',
618→        onAction: () => {
619→          setSettings({
620→            appearance: 'dark',
621→            windowWidth: 'medium',
622→            showRecentApps: true,
623→            showDock: true,
624→            fontSize: 'default',
