642→    showHUD,
643→    setTheme,
644→  ]);
645→
646→  const toggleActions = useCallback(() => {
647→    setActionsOpen(prev => !prev);
648→  }, []);
649→
650→  const closeActions = useCallback(() => {
651→    setActionsOpen(false);
652→  }, []);
653→
654→  useKeyboardShortcut(
655→    {
656→      key: 'k',
657→      meta: true,
658→    },
659→    toggleActions,
660→  );
661→
662→  const dropdownSections: DropdownSection[] = useMemo(() => {
663→    const sections: DropdownSection[] = [
664→      {
665→        title: 'Navigation',
666→        actions: [
667→          {
668→            label: 'General',
669→            onClick: () => {
670→              setActiveTab('general');
671→              setActionsOpen(false);
672→            },
673→          },
674→          {
675→            label: 'Extensions',
676→            onClick: () => {
677→              setActiveTab('extensions');
678→              setActionsOpen(false);
679→            },
680→          },
681→          {
682→            label: 'Advanced',
