691→
692→    if (activeTab === 'advanced') {
693→      sections.push({
694→        title: 'Actions',
695→        actions: [
696→          {
697→            label: 'Export Settings',
698→            onClick: handleExport,
699→          },
700→          {
701→            label: 'Import Settings',
702→            onClick: handleImport,
703→          },
704→          {
705→            label: 'Clear Cache',
706→            onClick: handleClearCache,
707→          },
