721→    handleClearCache,
722→    handleResetAll,
723→  ]);
724→
725→  return (
726→    <>
727→      <SearchBar
728→        value={query}
729→        onChange={handleQueryChange}
730→        placeholder={
731→          activeTab === 'extensions' ? 'Search Extensions...' : 'Settings'
732→        }
733→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
734→        dropdown={
735→          <SearchDropdown
736→            sections={TAB_SECTIONS}
