  1→import type { ReactNode } from 'react';
  2→import type { TagColor } from '../../constants/tag_colors';
  3→import { TAG_COLOR_HEX } from '../../constants/tag_colors';
  4→export type { TagColor } from '../../constants/tag_colors';
  5→
  6→interface TagColorValue {
  7→  background: string;
  8→  text: string;
  9→}
 10→
 11→const TAG_COLORS: Record<TagColor, TagColorValue> = {
 12→  blue: {
 13→    background: TAG_COLOR_HEX.blue,
 14→    text: '#ffffff',
 15→  },
 16→  green: {
 17→    background: TAG_COLOR_HEX.green,
 18→    text: '#ffffff',
 19→  },
 20→  orange: {
 21→    background: TAG_COLOR_HEX.orange,
 22→    text: '#1a1a1c',
 23→  },
 24→  red: {
 25→    background: TAG_COLOR_HEX.red,
 26→    text: '#ffffff',
 27→  },
 28→  purple: {
 29→    background: TAG_COLOR_HEX.purple,
 30→    text: '#ffffff',
 31→  },
 32→  yellow: {
 33→    background: TAG_COLOR_HEX.yellow,
 34→    text: '#1a1a1c',
 35→  },
 36→};
 37→
 38→export interface MetadataLabelProps {
 39→  title: string;
 40→  text?: string;
 41→  icon?: ReactNode;
 42→}
 43→
 44→export function MetadataLabel({ title, text, icon }: MetadataLabelProps) {
 45→  const hasValue = text || icon;
 46→
 47→  return (
 48→    <div className="detail-metadata__item">
 49→      <span className="detail-metadata__label">{title}</span>
 50→      {hasValue && (
 51→        <span className="detail-metadata__value">
 52→          {icon && <span className="detail-metadata__value-icon">{icon}</span>}
 53→          {text && <span className="detail-metadata__value-text">{text}</span>}
 54→        </span>
 55→      )}
 56→    </div>
 57→  );
 58→}
 59→
 60→export interface MetadataLinkProps {
 61→  title: string;
 62→  text: string;
 63→  target: string;
 64→}
 65→
 66→export function MetadataLink({ title, text, target }: MetadataLinkProps) {
 67→  return (
 68→    <div className="detail-metadata__item">
 69→      <span className="detail-metadata__label">{title}</span>
 70→      <a
 71→        className="detail-metadata__link"
 72→        href={target}
 73→        target="_blank"
 74→        rel="noopener noreferrer"
 75→      >
 76→        {text}
 77→      </a>
 78→    </div>
 79→  );
 80→}
 81→
 82→export interface MetadataTagProps {
 83→  text: string;
 84→  color?: TagColor;
 85→}
 86→
 87→export function MetadataTag({ text, color }: MetadataTagProps) {
 88→  return (
 89→    <span
 90→      className="detail-metadata__tag"
 91→      style={
 92→        color
 93→          ? {
 94→              backgroundColor: TAG_COLORS[color].background,
 95→              color: TAG_COLORS[color].text,
 96→            }
 97→          : undefined
 98→      }
 99→    >
100→      {text}
101→    </span>
102→  );
103→}
104→
105→export interface MetadataTagListProps {
106→  title: string;
107→  children: ReactNode;
108→}
109→
110→export function MetadataTagList({ title, children }: MetadataTagListProps) {
111→  return (
112→    <div className="detail-metadata__item">
113→      <span className="detail-metadata__label">{title}</span>
114→      <div className="detail-metadata__tags">{children}</div>
115→    </div>
116→  );
117→}
118→
119→export function MetadataSeparator() {
120→  return <hr className="detail-metadata__separator" />;
121→}
122→
123→export interface DetailMetadataProps {
124→  children: ReactNode;
125→}
126→
127→interface DetailMetadataComponent {
128→  (props: DetailMetadataProps): ReactNode;
129→  Label: typeof MetadataLabel;
130→  Link: typeof MetadataLink;
131→  TagList: typeof MetadataTagList;
132→  Tag: typeof MetadataTag;
133→  Separator: typeof MetadataSeparator;
134→}
135→
136→export const DetailMetadata: DetailMetadataComponent = Object.assign(
137→  function DetailMetadata({ children }: DetailMetadataProps) {
138→    return <div className="detail-metadata">{children}</div>;
139→  },
140→  {
141→    Label: MetadataLabel,
142→    Link: MetadataLink,
143→    TagList: MetadataTagList,
144→    Tag: MetadataTag,
145→    Separator: MetadataSeparator,
146→  },
147→);
